"use client"

import * as React from "react"

export type DockPosition = "left" | "right" | "bottom" | "floating"

export interface PanelState {
  id: string
  position: DockPosition
  floatingPosition?: {
    x: number
    y: number
    width?: number
    height?: number
  }
  zIndex?: number
  order?: number
}

export interface UseDockManagerOptions {
  defaultPosition?: DockPosition
  persistState?: boolean
  storageKey?: string
}

export interface UseDockManagerReturn {
  panels: Map<string, PanelState>
  dock: (
    panelId: string,
    position: DockPosition,
    options?: { floatingPosition?: PanelState["floatingPosition"] }
  ) => void
  undock: (panelId: string) => void
  getPanel: (panelId: string) => PanelState | undefined
  updatePanel: (panelId: string, updates: Partial<PanelState>) => void
  clear: () => void
}

const defaultZIndex = 1000
let globalZIndex = defaultZIndex

const panelStore = new Map<string, PanelState>()
const listeners = new Set<() => void>()

function subscribe(listener: () => void) {
  listeners.add(listener)
  return () => {
    listeners.delete(listener)
  }
}

function notify() {
  listeners.forEach((listener) => listener())
}

function loadFromStorage(key: string): Map<string, PanelState> {
  if (typeof window === "undefined") return new Map()

  try {
    const stored = localStorage.getItem(key)
    if (!stored) return new Map()

    const data = JSON.parse(stored)
    const map = new Map<string, PanelState>()
    Object.entries(data).forEach(([id, state]) => {
      map.set(id, state as PanelState)
    })
    return map
  } catch {
    return new Map()
  }
}

function saveToStorage(key: string, panels: Map<string, PanelState>) {
  if (typeof window === "undefined") return

  try {
    const data = Object.fromEntries(panels)
    localStorage.setItem(key, JSON.stringify(data))
  } catch {
    // Ignore storage errors
  }
}

export function useDockManager(
  options: UseDockManagerOptions = {}
): UseDockManagerReturn {
  const {
    defaultPosition = "right",
    persistState = false,
    storageKey = "dock-manager-state",
  } = options

  const [panels, setPanels] = React.useState<Map<string, PanelState>>(() => {
    if (persistState) {
      const stored = loadFromStorage(storageKey)
      if (stored.size > 0) {
        panelStore.clear()
        stored.forEach((state, id) => {
          panelStore.set(id, state)
        })
        return stored
      }
    }
    return new Map(panelStore)
  })

  React.useEffect(() => {
    const unsubscribe = subscribe(() => {
      setPanels(new Map(panelStore))
    })
    return unsubscribe
  }, [])

  React.useEffect(() => {
    if (persistState) {
      saveToStorage(storageKey, panels)
    }
  }, [panels, persistState, storageKey])

  const dock = React.useCallback(
    (
      panelId: string,
      position: DockPosition,
      options?: { floatingPosition?: PanelState["floatingPosition"] }
    ) => {
      const existingPanel = panelStore.get(panelId)
      const floatingPosition =
        options?.floatingPosition ??
        (existingPanel?.position === "floating"
          ? existingPanel.floatingPosition
          : undefined)

      const order =
        position === "floating"
          ? undefined
          : Array.from(panelStore.values()).filter(
              (p) => p.position === position
            ).length

      const panelState: PanelState = {
        id: panelId,
        position,
        floatingPosition,
        zIndex: position === "floating" ? ++globalZIndex : undefined,
        order,
      }

      panelStore.set(panelId, panelState)
      notify()
    },
    []
  )

  const undock = React.useCallback((panelId: string) => {
    panelStore.delete(panelId)
    notify()
  }, [])

  const getPanel = React.useCallback((panelId: string) => {
    return panelStore.get(panelId)
  }, [])

  const updatePanel = React.useCallback(
    (panelId: string, updates: Partial<PanelState>) => {
      const existing = panelStore.get(panelId)
      if (!existing) return

      const updated: PanelState = {
        ...existing,
        ...updates,
        id: panelId,
      }

      if (updates.position === "floating" && !updated.zIndex) {
        updated.zIndex = ++globalZIndex
      }

      if (updates.position && updates.position !== "floating") {
        updated.zIndex = undefined
        updated.order =
          Array.from(panelStore.values()).filter(
            (p) => p.position === updates.position && p.id !== panelId
          ).length + 1
      }

      panelStore.set(panelId, updated)
      notify()
    },
    []
  )

  const clear = React.useCallback(() => {
    panelStore.clear()
    if (persistState && typeof window !== "undefined") {
      localStorage.removeItem(storageKey)
    }
    notify()
  }, [persistState, storageKey])

  return {
    panels,
    dock,
    undock,
    getPanel,
    updatePanel,
    clear,
  }
}
